#include <stdio.h>
#include <stdlib.h>
#include <string.h>
typedef struct Node {
    char* data;
    struct Node** neighbors;
    int numNeighbors;
} Node;

Node* createNode(char* data) {
    Node* node = (Node*) malloc(sizeof(Node));
    node->data = data;
    node->neighbors = NULL;
    node->numNeighbors = 0;
    return node;
}

void addNeighbor(Node* node, Node* neighbor) {
    node->numNeighbors++;
    node->neighbors = (Node**) realloc(node->neighbors, node->numNeighbors * sizeof(Node*));
    node->neighbors[node->numNeighbors - 1] = neighbor;
}

int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    Node** nodes = (Node**) malloc(n * sizeof(Node*));
    for (int i = 0; i < n; i++) {
        char data[100];
        scanf("%s", data);
        nodes[i] = createNode(data);
    }
    for (int i = 0; i < m; i++) {
        int a, b;
        scanf("%d %d", &a, &b);
        addNeighbor(nodes[a - 1], nodes[b - 1]);
    }
    // Solve queries
    return 0;
}

