const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let lines = [];
rl.on('line', (input) => {
    lines.push(input);
});
rl.on('close', () => {
    let [n, m] = lines[0].split(' ').map(Number);
    let nodes = [];
    for (let i = 1; i <= n; i++) {
        nodes.push(new Node(lines[i]));
    }
    for (let i = n + 1; i <= n + m; i++) {
        let [a, b] = lines[i].split(' ').map(Number);
        nodes[a - 1].addNeighbor(nodes[b - 1]);
    }
    // Solve queries
